import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, CheckCircle, XCircle, FileText, Clock, AlertTriangle, Check, Eye } from 'lucide-react';
import { Button } from '../../components/common/Button';
import { Card } from '../../components/common/Card';
import { ImageViewer } from '../../components/common/ImageViewer';
import { DocumentViewer } from '../../components/common/DocumentViewer';
import { MediaViewer } from '../../components/common/MediaViewer';
import { getApplicationById, getApplicationHistory, getApplicationRequiredDocuments, downloadApplicationPdf } from '../../services/admin.service';
import toast from 'react-hot-toast';
import { format } from 'date-fns';
import { PUBLIC_FILE_BASE_URL } from '../../config/appConfig';
import { formatDateIST, formatDateISTNoTime } from '../../utils/date';

const ApplicationView = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [application, setApplication] = useState(null);
  const [loading, setLoading] = useState(true);
  const [statusHistory, setStatusHistory] = useState([]);
  const [requiredDocs, setRequiredDocs] = useState([]);
  const [includeImagesInPdf, setIncludeImagesInPdf] = useState(true);
  const [downloadingPdf, setDownloadingPdf] = useState(false);

  const statusColors = {
    'DRAFT': 'bg-gray-100 text-gray-700',
    'SUBMITTED': 'bg-blue-100 text-blue-700',
    'ELIGIBLE': 'bg-green-100 text-green-700',
    'NOT_ELIGIBLE': 'bg-red-100 text-red-700',
    'ON_HOLD': 'bg-amber-100 text-amber-700',
    'REJECTED': 'bg-red-200 text-red-800',
    'SELECTED': 'bg-emerald-100 text-emerald-700',
    'WAITLISTED': 'bg-purple-100 text-purple-700'
  };

  const fetchApplication = async () => {
    try {
      const data = await getApplicationById(id);
      setApplication(data);
    } catch (error) {
      toast.error('Failed to load application details');
      navigate('/applications');
    } finally {
      setLoading(false);
    }
  };

  const fetchHistory = async () => {
    try {
      const history = await getApplicationHistory(id);
      setStatusHistory(Array.isArray(history) ? history : []);
    } catch (error) {
      console.error('Failed to load history', error);
    }
  };

  const fetchRequiredDocuments = async () => {
    try {
      const docs = await getApplicationRequiredDocuments(id);
      setRequiredDocs(Array.isArray(docs) ? docs : []);
    } catch (error) {
      setRequiredDocs([]);
    }
  };

  useEffect(() => {
    fetchApplication();
    fetchHistory();
    fetchRequiredDocuments();
  }, [id]);

  // img setup code
  const BASE_URL = PUBLIC_FILE_BASE_URL;

  const fileUrl = (path) => {
    if (!path) return null;

    // remove accidental leading slash
    const cleanPath = path.replace(/^\/+/, '');

    return `${BASE_URL}/${cleanPath}`;
  };

  const isImageFile = (mimeType) => mimeType && mimeType.startsWith('image/');

  const isImagePath = (path) => {
    if (!path) return false;
    return /\.(png|jpe?g|gif|webp|bmp)$/i.test(path);
  };




  // Check if actions are allowed
  const canTakeAction = application && ['ELIGIBLE', 'ON_HOLD'].includes(application.status);

  if (loading) {
    return <div className="p-6 text-center">Loading application details...</div>;
  }

  if (!application) return null;

  const { applicant, post, district, status, eligibility } = application;
  const personal = applicant?.personal || {};
  const address = applicant?.address || {};
  const education = applicant?.education || [];
  const experience = applicant?.experience || [];
  const skills = applicant?.skills || [];
  const documents = applicant?.documents || [];

  const findDocByCode = (code) =>
    documents.find(
      (doc) =>
        doc?.doc_type === code ||
        doc?.doc_type_id === code ||
        doc?.documentType?.doc_type_code === code ||
        doc?.documentType?.doc_code === code ||
        doc?.doc_code === code ||
        doc?.doc_type_code === code
    );

  const requiredDocTypeIds = new Set((requiredDocs || []).map((d) => d?.doc_type_id).filter(Boolean));
  // PAN temporarily disabled
  const corePersonalCodes = new Set(['PHOTO', 'SIGNATURE', 'AADHAAR', 'RESUME', 'DOMICILE']);
  const getDocCode = (doc) =>
    doc?.documentType?.doc_code ||
    doc?.documentType?.doc_type_code ||
    doc?.doc_code ||
    doc?.doc_type_code ||
    doc?.doc_type ||
    null;
  const extraDocuments = documents.filter((doc) => {
    const code = getDocCode(doc);
    if (code && corePersonalCodes.has(code)) return false;
    if (doc?.doc_type_id && requiredDocTypeIds.has(doc.doc_type_id)) return false;
    return true;
  });

  const meritScore = Number(application.merit_score);
  const hasMeritScore = Number.isFinite(meritScore);

  const photoDoc = documents.find(doc => doc.doc_type === 'PHOTO');
  const signatureDoc = documents.find(doc => doc.doc_type === 'SIGNATURE');
  const aadhaarDoc = findDocByCode('AADHAAR');
  // PAN temporarily disabled
  // const panDoc = findDocByCode('PAN');
  const resumeDoc = findDocByCode('RESUME');
  const domicileDoc = findDocByCode('DOMICILE');

  const photoPath = personal?.photo_path || photoDoc?.file_path || null;
  const signaturePath = personal?.signature_path || signatureDoc?.file_path || null;
  const aadhaarFilePath = personal?.aadhaar_path || aadhaarDoc?.file_path || null;
  // PAN temporarily disabled
  const panFilePath = null;
  const resumeFilePath = personal?.resume_path || resumeDoc?.file_path || null;
  const domicileFilePath = personal?.domicile_path || domicileDoc?.file_path || null;

  const categoryName =
    personal?.categoryMaster?.category_name ||
    personal?.category_name ||
    personal?.category ||
    '-';

  const handleDownloadPdf = async () => {
    try {
      setDownloadingPdf(true);
      const response = await downloadApplicationPdf(id, { include_images: includeImagesInPdf });
      const blob = new Blob([response.data], { type: 'application/pdf' });
      const url = window.URL.createObjectURL(blob);

      const appNo = application?.application_no || id;
      const a = document.createElement('a');
      a.href = url;
      a.download = `application_${appNo}.pdf`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      window.URL.revokeObjectURL(url);
    } catch (err) {
      toast.error(err?.response?.data?.message || err?.message || 'Failed to download PDF');
    } finally {
      setDownloadingPdf(false);
    }
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto pb-10">
      {/* Header with Actions */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <Button variant="ghost" size="sm" onClick={() => navigate(-1)}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <h1 className="text-2xl font-bold text-slate-900">
              Application #{application.application_no}
            </h1>
            <div className="flex flex-wrap gap-2 text-sm text-slate-500 mt-1">
              <span>{post?.post_name}</span>
              <span>•</span>
              <span>{district?.district_name}</span>
              <span>•</span>
              <span className={`inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${statusColors[status] || 'bg-gray-100'}`}>
                {status?.replace(/_/g, ' ')}
              </span>
              {/* {hasMeritScore && (
                <>
                  <span>•</span>
                  <span className="font-medium text-blue-600">
                    Merit Score: {meritScore.toFixed(2)}
                  </span>
                </>
              )} */}
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <label className="flex items-center gap-2 text-sm text-slate-700">
            <input
              type="checkbox"
              checked={includeImagesInPdf}
              onChange={(e) => setIncludeImagesInPdf(e.target.checked)}
            />
            Include photo/signature
          </label>

          <Button
            variant="outline"
            onClick={handleDownloadPdf}
            disabled={downloadingPdf}
            leftIcon={<FileText className="h-4 w-4" />}
          >
            {downloadingPdf ? 'Downloading...' : 'Download PDF'}
          </Button>
        </div>
      </div>

      {/* Eligibility Status Card */}
      {eligibility && (
        <Card title="Eligibility Status">
          <div className="p-4">
            <div className="flex items-start gap-3">
              {eligibility.is_eligible ? (
                <>
                  <CheckCircle className="h-6 w-6 text-green-600 flex-shrink-0" />
                  <div className="flex-1">
                    <p className="font-semibold text-green-700">Eligible</p>
                    <p className="text-sm text-slate-700 mt-1">
                      <span className="font-medium">Post:</span> {post?.post_name || 'N/A'}
                    </p>
                    <p className="text-xs text-slate-500 mt-1">
                      Checked on {formatDateIST(eligibility.checked_at) || 'N/A'}
                    </p>
                  </div>
                </>
              ) : (
                <>
                  <XCircle className="h-6 w-6 text-red-600 flex-shrink-0" />
                  <div className="flex-1">
                    <p className="font-semibold text-red-700">Not Eligible</p>
                    {application.system_eligibility_reason ? (
                      <p className="text-sm text-slate-600 mt-2">
                        <span className="font-medium">Reason:</span> {application.system_eligibility_reason}
                      </p>
                    ) : eligibility.rejection_reasons && (
                      <p className="text-sm text-slate-600 mt-2">
                        <span className="font-medium">Reason:</span> {eligibility.rejection_reasons}
                      </p>
                    )}
                  </div>
                </>
              )}
            </div>
          </div>
        </Card>
      )}


      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Personal & Address */}
        <div className="lg:col-span-1 space-y-6">
          <Card title="Personal Details">
            <div className="space-y-4 text-sm">
              {/* Photo */}
              {photoPath && (
                <div className="flex justify-center mb-4">
                  <ImageViewer
                    src={photoPath}
                    alt="Applicant Photo"
                    className="w-32 h-32 rounded-lg object-cover"
                    showPreview={true}
                  />
                </div>
              )}

              {/* Signature */}
              {signaturePath && (
                <div className="flex justify-center -mt-2 mb-2">
                  <ImageViewer
                    src={signaturePath}
                    alt="Applicant Signature"
                    className="w-40 h-14 rounded-lg object-contain bg-white"
                    showPreview={true}
                  />
                </div>
              )}

              <div>
                <label className="text-xs text-slate-500 uppercase">Full Name</label>
                <p className="font-medium">{personal.full_name || '-'}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs text-slate-500 uppercase">Gender</label>
                  <p className="font-medium">{application.gender || personal.gender || '-'}</p>
                </div>
                <div>
                  <label className="text-xs text-slate-500 uppercase">Age</label>
                  <p className="font-medium">{personal.age || '-'}</p>
                </div>
              </div>
              <div>
                <label className="text-xs text-slate-500 uppercase">Date of Birth</label>
                <p className="font-medium">
                  {formatDateISTNoTime(application.date_of_birth || personal.dob)}
                </p>
              </div>
              <div>
                <label className="text-xs text-slate-500 uppercase">Category</label>
                <p className="font-medium">{categoryName}</p>
              </div>
              <div>
                <label className="text-xs text-slate-500 uppercase">Aadhaar Number</label>
                <p className="font-medium">{application.aadhaar_number || personal.aadhar_no || '-'}</p>
              </div>
              {/* PAN temporarily disabled */}
              {/* <div>
                <label className="text-xs text-slate-500 uppercase">PAN Number</label>
                <p className="font-medium">{application.pan_no || personal.pan_no || '-'}</p>
              </div> */}
              <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                <span className="text-xs text-slate-500 uppercase">Aadhaar File</span>
                {aadhaarFilePath ? (
                  <DocumentViewer src={aadhaarFilePath} fileName="Aadhaar" variant="link" />
                ) : (
                  <span className="text-sm text-slate-500">-</span>
                )}
              </div>
              {/* PAN file temporarily disabled */}
              {/* <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                <span className="text-xs text-slate-500 uppercase">PAN File</span>
                {panFilePath ? (
                  <DocumentViewer src={panFilePath} fileName="PAN Card" variant="link" />
                ) : (
                  <span className="text-sm text-slate-500">-</span>
                )}
              </div> */}
              <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                <span className="text-xs text-slate-500 uppercase">Resume</span>
                {resumeFilePath ? (
                  <DocumentViewer src={resumeFilePath} fileName="Resume" variant="link" />
                ) : (
                  <span className="text-sm text-slate-500">-</span>
                )}
              </div>
              <div className="flex flex-col sm:flex-row sm:justify-between py-2 border-b border-gray-100 last:border-0">
                <span className="text-xs text-slate-500 uppercase">Domicile Certificate</span>
                {domicileFilePath ? (
                  <DocumentViewer src={domicileFilePath} fileName="Domicile Certificate" variant="link" />
                ) : (
                  <span className="text-sm text-slate-500">-</span>
                )}
              </div>
              <div>
                <label className="text-xs text-slate-500 uppercase">Email</label>
                <p className="font-medium">{applicant?.email || '-'}</p>
              </div>
              <div>
                <label className="text-xs text-slate-500 uppercase">Mobile</label>
                <p className="font-medium">{applicant?.mobile_no || '-'}</p>
              </div>
            </div>
          </Card>

          <Card title="Address">
            <div className="space-y-2 text-sm">
              <p>{address.address_line || '-'}</p>
              {address.address_line2 && <p>{address.address_line2}</p>}
              <p>
                {(address?.taluka?.taluka_name || '-')}
                {address?.district?.district_name ? `, ${address.district.district_name}` : ''}
              </p>
              <p className="font-medium">Pin: {address.pincode || '-'}</p>
              <div className="mt-3 pt-3 border-t">
                <label className="text-xs text-slate-500 uppercase">Selected District (Application)</label>
                <p className="font-medium">{district?.district_name || '-'}</p>
              </div>
              {address.permanent_address_same === false && (
                <div className="mt-3 pt-3 border-t">
                  <label className="text-xs text-slate-500 uppercase">Permanent Address</label>
                  <p>{address.permanent_address_line || '-'}</p>
                  {address.permanent_address_line2 && <p>{address.permanent_address_line2}</p>}
                  <p>
                    {(address?.permanentTaluka?.taluka_name || '-')}
                    {address?.permanentDistrict?.district_name ? `, ${address.permanentDistrict.district_name}` : ''}
                  </p>
                  <p className="font-medium">Pin: {address.permanent_pincode || '-'}</p>
                </div>
              )}
            </div>
          </Card>
        </div>

        {/* Right Column: Education, Experience, Docs */}
        <div className="lg:col-span-2 space-y-6">
          <Card title="Education">
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                  <tr>
                    <th className="px-4 py-2">Education Level</th>
                    <th className="px-4 py-2">Degree</th>
                    {/* <th className="px-4 py-2">Specialization</th> */}
                    <th className="px-4 py-2">University/Board</th>
                    <th className="px-4 py-2">Year</th>
                    <th className="px-4 py-2">Percentage</th>
                    <th className="px-4 py-2">Certificate</th>
                  </tr>
                </thead>
                <tbody>
                  {education.map((edu, idx) => (
                    <tr key={idx} className="border-b last:border-0">
                      <td className="px-4 py-2">{edu.educationLevel?.level_name || edu.qualification_level || '-'}</td>
                      <td className="px-4 py-2 font-medium">{edu.degree_name || edu.stream_subject || '-'}</td>
                      {/* <td className="px-4 py-2">{edu.specialization || '-'}</td> */}
                      <td className="px-4 py-2">{edu.university_board || '-'}</td>
                      <td className="px-4 py-2">{edu.passing_year || '-'}</td>
                      <td className="px-4 py-2">{edu.percentage ? `${edu.percentage}%` : '-'}</td>
                      <td className="px-4 py-2">
                        {edu.certificate_path ? (
                          <DocumentViewer src={edu.certificate_path} fileName="Education Certificate" variant="link" />
                        ) : (
                          <span className="text-slate-400">-</span>
                        )}
                      </td>
                    </tr>
                  ))}
                  {education.length === 0 && (
                    <tr><td colSpan="6" className="px-4 py-2 text-center text-slate-500">No education records found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </Card>

          <Card title="Experience">
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                  <tr>
                    <th className="px-4 py-2">Organization</th>
                    <th className="px-4 py-2">Designation</th>
                    <th className="px-4 py-2">Duration</th>
                    <th className="px-4 py-2">Total Months</th>
                    <th className="px-4 py-2">Certificate</th>
                  </tr>
                </thead>
                <tbody>
                  {experience.map((exp, idx) => (
                    <tr key={idx} className="border-b last:border-0">
                      <td className="px-4 py-2 font-medium">{exp.organization_name}</td>
                      <td className="px-4 py-2">{exp.designation}</td>
                      <td className="px-4 py-2">
                        {formatDateISTNoTime(exp.start_date) || '-'} - {exp.is_current ? 'Present' : formatDateISTNoTime(exp.end_date) || '-'}
                      </td>
                      <td className="px-4 py-2">{exp.total_months || '-'} months</td>
                      <td className="px-4 py-2">
                        {exp.certificate_path ? (
                          <DocumentViewer src={exp.certificate_path} fileName="Experience Certificate" variant="link" />
                        ) : (
                          <span className="text-slate-400">-</span>
                        )}
                      </td>
                    </tr>
                  ))}
                  {experience.length === 0 && (
                    <tr><td colSpan="5" className="px-4 py-2 text-center text-slate-500">No experience records found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </Card>

          <Card title="Skills">
            <div className="overflow-x-auto">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                  <tr>
                    <th className="px-4 py-2">Skill</th>
                    <th className="px-4 py-2">Notes</th>
                    <th className="px-4 py-2">Certificate</th>
                  </tr>
                </thead>
                <tbody>
                  {skills.map((s, idx) => (
                    <tr key={s.applicant_skill_id || idx} className="border-b last:border-0">
                      <td className="px-4 py-2 font-medium">{s?.skill?.skill_name || s?.skill_name || '-'}</td>
                      <td className="px-4 py-2">{s?.notes || '-'}</td>
                      <td className="px-4 py-2">
                        {s?.certificate_path ? (
                          <MediaViewer src={s.certificate_path} fileName="Skill Certificate" variant="link" />
                        ) : (
                          <span className="text-slate-400">-</span>
                        )}
                      </td>
                    </tr>
                  ))}
                  {skills.length === 0 && (
                    <tr><td colSpan="3" className="px-4 py-2 text-center text-slate-500">No skills found</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </Card>

          <Card title="Documents">
            <div className="space-y-4">
              <div>
                <div className="text-sm font-medium text-slate-800 mb-2">Post Required Documents</div>
                {requiredDocs.length > 0 ? (
                  <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                      <thead className="text-xs text-slate-500 uppercase bg-slate-50">
                        <tr>
                          <th className="px-4 py-2">Document</th>
                          <th className="px-4 py-2">Required</th>
                          <th className="px-4 py-2">Uploaded</th>
                          <th className="px-4 py-2">Action</th>
                        </tr>
                      </thead>
                      <tbody>
                        {requiredDocs.map((d) => (
                          <tr key={d.doc_type_id} className="border-b last:border-0">
                            <td className="px-4 py-2 font-medium">{d.doc_type_name || d.doc_type_name_mr || d.doc_code || '-'}</td>
                            <td className="px-4 py-2">
                              {d.required_for_post ? (
                                <span className="inline-flex px-2 py-0.5 rounded text-xs bg-blue-100 text-blue-700">Post</span>
                              ) : (
                                <span className="inline-flex px-2 py-0.5 rounded text-xs bg-slate-100 text-slate-700">Common</span>
                              )}
                            </td>
                            <td className="px-4 py-2">
                              {d.uploaded ? (
                                <span className="inline-flex items-center gap-1 text-xs text-green-700">
                                  <Check className="h-3 w-3" /> Yes
                                </span>
                              ) : (
                                <span className="inline-flex items-center gap-1 text-xs text-amber-700">
                                  <AlertTriangle className="h-3 w-3" /> No
                                </span>
                              )}
                            </td>
                            <td className="px-4 py-2">
                              {d.uploaded_document ? (
                                <DocumentViewer src={d.uploaded_document.file_path} fileName={d.doc_type_name || 'Document'} variant="link" />
                              ) : (
                                <span className="text-slate-400">-</span>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                ) : (
                  <div className="p-4 text-center text-slate-500 bg-slate-50 rounded border border-dashed">
                    No required documents configured for this post
                  </div>
                )}
              </div>

              <div>
                <div className="text-sm font-medium text-slate-800 mb-2">Extra Documents</div>
                {extraDocuments.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                    {extraDocuments.map((doc, idx) => (
                      <div key={idx} className="border rounded-lg p-3 hover:shadow-md transition-shadow">
                        <div className="flex items-start justify-between mb-2">
                          <div className="flex-1">
                            <h4 className="font-medium text-xs text-slate-900 line-clamp-2">
                              {doc.documentType?.doc_type_name || doc.doc_type}
                            </h4>
                            {doc.is_verified && (
                              <span className="inline-flex items-center gap-1 text-xs text-green-600 mt-1">
                                <Check className="h-3 w-3" /> Verified
                              </span>
                            )}
                          </div>
                        </div>
                        <div className="mt-2">
                          <MediaViewer
                            src={doc.file_path}
                            fileName={doc.documentType?.doc_type_name || doc.doc_type}
                            variant="card"
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="p-4 text-center text-slate-500 bg-slate-50 rounded border border-dashed">
                    No extra documents uploaded
                  </div>
                )}
              </div>
            </div>
          </Card>
        </div>
      </div>

      {/* Status History Card - NEW */}
      {statusHistory.length > 0 && (
        <Card title="Status History">
          <div className="p-4">
            <div className="space-y-3">
              {statusHistory.map((h, idx) => (
                <div key={h.history_id || idx} className="flex items-start gap-3 pb-3 border-b last:border-0">
                  <Clock className="h-4 w-4 text-slate-400 mt-1 flex-shrink-0" />
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <span className={`px-2 py-0.5 rounded text-xs font-medium ${statusColors[h.old_status] || 'bg-gray-100'}`}>
                        {h.old_status || 'NEW'}
                      </span>
                      <span className="text-slate-400">→</span>
                      <span className={`px-2 py-0.5 rounded text-xs font-medium ${statusColors[h.new_status] || 'bg-gray-100'}`}>
                        {h.new_status}
                      </span>
                    </div>
                    <p className="text-xs text-slate-500 mt-1">
                      {h.changed_by_type === 'SYSTEM' ? 'System' : h.changedByUser?.full_name || 'Admin'} •
                      {formatDateIST(/Z|[+-]\d\d:?\d\d$/.test(h.created_at || '') ? h.created_at : `${h.created_at}Z`) || ''}
                    </p>
                    {h.remarks && (
                      <p className="text-sm text-slate-600 mt-1">{h.remarks}</p>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </Card>
      )}

    </div>
  );
};

export default ApplicationView;
